 1→import { MemorySaver } from "@langchain/langgraph";
 2→import { MultiServerMCPClient } from "@langchain/mcp-adapters";
 3→import { createDeepAgent } from "deepagents";
 4→import { createAgent, DynamicStructuredTool } from "langchain";
 5→import { createToolErrorMiddleware } from "../middleware/tool-error.middleware";
 6→import { ConversationSandboxManager } from '../sandbox/conversation-sandbox.manager';
 7→import { BaseLanguageModel } from "@langchain/core/language_models/base";
 8→import { SANDBOX_SKILLS_ROOT } from '../sandbox/sandbox-skills.config';
 9→import { configSchema } from "../../config/config.schema";
10→
11→const memory = new MemorySaver();
12→
13→
14→
15→export default async function createSimpleDeepAgent(
16→  model: BaseLanguageModel,
17→  conversationId: string,
18→  sandboxManager: ConversationSandboxManager,
19→): Promise<ReturnType<typeof createAgent>> {
20→  const session = await sandboxManager.getConversationSandbox(conversationId);
21→  const client = new MultiServerMCPClient({
22→    grafana: {
23→      transport: 'sse',
24→      url: configSchema.GRAFANA_MCP_URL!,
25→    },
26→  });
27→
28→  // 过滤，只剩下
29→  const FILTER_TOOLS = ['search_dashboards', 'list_datasources', 'get_dashboard_panel_queries', 'query_prometheus', 'list_prometheus_label_names', 'generate_deeplink', 'get_dashboard_by_uid'];
30→  const allMcpTools = (await client.getTools()).filter(tool => FILTER_TOOLS.includes(tool.name)) as DynamicStructuredTool[]
31→
32→  const middleware = [
33→    createToolErrorMiddleware(),
34→  ]
35→
36→  return createDeepAgent({
37→    model: model,
38→    tools: allMcpTools,
39→    middleware,
40→    backend: session.backend,
41→    checkpointer: memory,
42→    skills: [SANDBOX_SKILLS_ROOT]
43→  });
44→}
