 54→@Injectable({ scope: Scope.DEFAULT })
 55→export class AgentsService {
 56→  constructor(private readonly sandboxManager: ConversationSandboxManager) {}
 57→
 58→  private saver = new MemorySaver();
 59→
 60→  async *run(input: string | unknown | undefined, options: IGraphOptions): AsyncGenerator<IGraphEvent> {
 61→    const graph = await this.createGraph(options.model, options.conversation_id);
 62→    const graphInput = (typeof input === 'string' ? { messages: [new HumanMessage(input)] } : input ?? null) 
 63→    const stream = graph.streamEvents(
 64→      graphInput,
 65→      {
 66→        version: 'v2' as const,
 67→        signal: options.signal,
 68→        maxConcurrency:4,
 69→        configurable: { thread_id: options.conversation_id },
 70→        ...{
 71→          metadata: { logid: options.request.logId || randomUUID() },
 72→        }
 73→      } ,
 74→    );
 75→
 76→    const toolState: ToolInputState = { inputtingTool: undefined, subagentNamespaces: {} };
 77→    for await (const streamEvent of stream) {
 78→      if (!streamEvent || typeof streamEvent !== 'object' || ArrayBuffer.isView(streamEvent)) {
 79→        warn({ streamEventType: typeof streamEvent }, 'Unexpected non-object stream event');
 80→        continue;
 81→      }
 82→
 83→      const { run_id, name, event, data, metadata } = streamEvent as {
 84→        run_id: string;
 85→        name: string;
 86→        event: string;
 87→        data: unknown;
 88→        metadata?: Record<string, unknown>;
 89→      };
 90→
 91→
 92→      const node = resolveNode(metadata);
 93→      const graphEvent = dispatchStreamEvent(
 94→        event,
 95→        { run_id, name, data: data as Record<string, unknown>, node, metadata },
 96→        toolState,
 97→      );
 98→      if (graphEvent) yield graphEvent;
 99→    }
100→  }
101→
102→  private createGraph(model: EModelName, conversationId: string) {
103→    return createSimpleDeepAgent(getModel(model), conversationId, this.sandboxManager);
104→  }
105→}
