 1→import { VfsSandbox } from '@langchain/node-vfs';
 2→import { TextDecoder } from 'node:util';
 3→import type { ConversationSandboxFactory, ConversationSandboxSession } from './base-sandbox';
 4→import {
 5→  CompositeSandboxInitialFilesProvider,
 6→  LocalSkillsSandboxInitialFilesProvider,
 7→  type SandboxInitialFiles,
 8→  type SandboxInitialFilesProvider,
 9→} from './initial-files.provider';
10→
11→interface NodeVfsConversationSandboxFactoryOptions {
12→  skillsRoot?: string;
13→  initialFilesProvider?: SandboxInitialFilesProvider;
14→}
15→
16→function normalizeListedSandboxPath(filePath: string) {
17→  return filePath.replace(/^\.?\//, '').replace(/\/$/, '').replace(/\\/g, '/');
18→}
19→
20→function normalizeSandboxFilePath(relativePath: string) {
21→  const normalized = relativePath.replace(/\\/g, '/').replace(/^\/+/, '');
22→  if (!normalized || normalized === '.' || normalized === '..' || normalized.startsWith('../')) {
23→    throw new Error('Invalid session file path');
24→  }
25→  return normalized;
26→}
27→
28→class NodeVfsConversationSandboxSession implements ConversationSandboxSession {
29→  private readonly decoder = new TextDecoder();
30→
31→  constructor(readonly backend: VfsSandbox) {}
32→
33→  get workingDirectory() {
34→    return this.backend.workingDirectory;
35→  }
36→
37→  static async create(initialFiles?: SandboxInitialFiles) {
38→    const backend = await VfsSandbox.create({ initialFiles });
39→    return new NodeVfsConversationSandboxSession(backend);
40→  }
41→
42→  async listFiles() {
43→    const entries = await this.backend.globInfo('**/*', '/');
44→    return entries
45→      .filter(entry => !entry.is_dir)
46→      .map(entry => normalizeListedSandboxPath(entry.path))
47→      .sort((a, b) => a.localeCompare(b));
48→  }
49→
50→  async readFile(relativePath: string) {
51→    const normalizedPath = normalizeSandboxFilePath(relativePath);
52→    const [result] = await this.backend.downloadFiles([normalizedPath]);
53→    if (!result || result.error || !result.content) {
54→      throw new Error(`Session file not found: ${normalizedPath}`);
55→    }
56→    return this.decoder.decode(result.content);
57→  }
58→
59→  async stop() {
60→    await this.backend.stop();
61→  }
62→}
63→
64→export class NodeVfsConversationSandboxFactory implements ConversationSandboxFactory {
65→  private readonly initialFilesProvider: SandboxInitialFilesProvider;
66→
67→  constructor(options: NodeVfsConversationSandboxFactoryOptions = {}) {
68→    this.initialFilesProvider = options.initialFilesProvider ?? new CompositeSandboxInitialFilesProvider([
69→      new LocalSkillsSandboxInitialFilesProvider({ skillsRoot: options.skillsRoot }),
70→      // Future TOS-backed skill uploads should be exposed as another
71→      // SandboxInitialFilesProvider and appended here.
72→    ]);
73→  }
74→
75→  async createConversationSandbox(_conversationId: string) {
76→    return NodeVfsConversationSandboxSession.create(await this.initialFilesProvider.getInitialFiles());
77→  }
78→}
