329→export function handleToolStart(
330→  runId: string,
331→  name: string,
332→  data: { input: { input: string } },
333→  node: ENodeName | undefined,
334→  state: ToolInputState,
335→  subagent?: StreamSubagentInfo,
336→): IGraphEvent | undefined {
337→  state.inputtingTool = undefined;
338→  log(`tool-start: ${name}`);
339→
340→  // ask-user 工具发出专属事件，前端将其强制展示（不折叠）
341→  if (name === EToolName.AskUser) {
342→    return undefined;
343→  }
344→
345→  const input: string = data.input.input;
346→  log(`tool-call(${name}): ${input}`);
347→
348→  return makeEvent('tool-call', node, { id: runId, name, input }, subagent);
349→}
