351→export function handleToolEnd(
352→  runId: string,
353→  name: string,
354→  data: { output: { artifact: unknown; content: unknown } },
355→  node: ENodeName | undefined,
356→  subagent?: StreamSubagentInfo,
357→): IGraphEvent | undefined {
358→  if (name === EToolName.AskUser) {
359→    return undefined;
360→  }
361→
362→  const { artifact, content } = data.output;
363→
364→  if (artifact instanceof Error) {
365→    log(`tool-call-result(${name}).error: ${artifact.message}`);
366→  } else {
367→    log(`tool-call-result(${name}).artifact: ${tryJSONStringify(artifact) ?? 'undefined'}`);
368→  }
369→  log(`tool-call-result(${name}).content: ${content}`);
370→
371→  const output = resolveToolOutput(artifact, content);
372→  const toolError = extractToolError(artifact) ?? extractToolError(output);
373→  const outputStr = artifact instanceof Error
374→    ? (artifact as Error).message
375→    : toolError ?? (typeof output === 'string' ? output : tryJSONStringify(output) ?? '');
376→  const outputLength = outputStr.length;
377→  const summarizedOutput = shouldSummarizeToolCallResult(name)
378→    ? summarizeToolCallResult(outputStr)
379→    : outputStr;
380→
381→  return makeEvent('tool-call-result', node, {
382→    id: runId,
383→    name,
384→    outputLength,
385→    ...(artifact instanceof Error || toolError
386→      ? { error: summarizedOutput }
387→      : { output: shouldSummarizeToolCallResult(name) ? summarizedOutput : output }),
388→  }, subagent);
389→}
390→
391→export function handleToolError(
392→  runId: string,
393→  name: string,
394→  data: { error?: unknown },
395→  node: ENodeName | undefined,
396→  subagent?: StreamSubagentInfo,
397→): IGraphEvent | undefined {
398→  if (name === EToolName.AskUser) {
399→    return undefined;
400→  }
401→
402→  const message = extractToolError(data.error) ?? tryJSONStringify(data.error) ?? 'Tool execution failed';
403→  log(`tool-call-result(${name}).error: ${message}`);
404→  const summarizedMessage = shouldSummarizeToolCallResult(name)
405→    ? summarizeToolCallResult(message)
406→    : message;
407→
408→  return makeEvent('tool-call-result', node, {
409→    id: runId,
410→    name,
411→    outputLength: message.length,
412→    error: summarizedMessage,
413→  }, subagent);
414→}
