import { VfsSandbox } from '@langchain/node-vfs';
import { TextDecoder } from 'node:util';
import type { ConversationSandboxFactory, ConversationSandboxSession } from './base-sandbox';
import {
  CompositeSandboxInitialFilesProvider,
  LocalSkillsSandboxInitialFilesProvider,
  type SandboxInitialFiles,
  type SandboxInitialFilesProvider,
} from './initial-files.provider';

interface NodeVfsConversationSandboxFactoryOptions {
  skillsRoot?: string;
  initialFilesProvider?: SandboxInitialFilesProvider;
}

function normalizeListedSandboxPath(filePath: string) {
  return filePath.replace(/^\.?\//, '').replace(/\/$/, '').replace(/\\/g, '/');
}

function normalizeSandboxFilePath(relativePath: string) {
  const normalized = relativePath.replace(/\\/g, '/').replace(/^\/+/, '');
  if (!normalized || normalized === '.' || normalized === '..' || normalized.startsWith('../')) {
    throw new Error('Invalid session file path');
  }
  return normalized;
}

class NodeVfsConversationSandboxSession implements ConversationSandboxSession {
  private readonly decoder = new TextDecoder();

  constructor(readonly backend: VfsSandbox) {}

  get workingDirectory() {
    return this.backend.workingDirectory;
  }

  static async create(initialFiles?: SandboxInitialFiles) {
    const backend = await VfsSandbox.create({ initialFiles });
    return new NodeVfsConversationSandboxSession(backend);
  }

  async listFiles() {
    const entries = await this.backend.globInfo('**/*', '/');
    return entries
      .filter(entry => !entry.is_dir)
      .map(entry => normalizeListedSandboxPath(entry.path))
      .sort((a, b) => a.localeCompare(b));
  }

  async readFile(relativePath: string) {
    const normalizedPath = normalizeSandboxFilePath(relativePath);
    const [result] = await this.backend.downloadFiles([normalizedPath]);
    if (!result || result.error || !result.content) {
      throw new Error(`Session file not found: ${normalizedPath}`);
    }
    return this.decoder.decode(result.content);
  }

  async stop() {
    await this.backend.stop();
  }
}

export class NodeVfsConversationSandboxFactory implements ConversationSandboxFactory {
  private readonly initialFilesProvider: SandboxInitialFilesProvider;

  constructor(options: NodeVfsConversationSandboxFactoryOptions = {}) {
    this.initialFilesProvider = options.initialFilesProvider ?? new CompositeSandboxInitialFilesProvider([
      new LocalSkillsSandboxInitialFilesProvider({ skillsRoot: options.skillsRoot }),
      // Future TOS-backed skill uploads should be exposed as another
      // SandboxInitialFilesProvider and appended here.
    ]);
  }

  async createConversationSandbox(_conversationId: string) {
    return NodeVfsConversationSandboxSession.create(await this.initialFilesProvider.getInitialFiles());
  }
}

